import json
import unittest
from pathlib import Path
from src.webhooks import canonical_event

ROOT = Path(__file__).parents[1]

class WebhookTests(unittest.TestCase):
    def test_all_provider_samples(self):
        expected = {
            'acme': {'id':'evt-a1','type':'invoice_paid','account_id':'acct-7','occurred_at':'2026-04-01T10:00:00Z'},
            'orbit': {'id':'evt-o2','type':'subscription_cancelled','account_id':'acct-8','occurred_at':'2026-04-02T11:30:00Z'},
            'zenith': {'id':'evt-z3','type':'user_created','account_id':'acct-9','occurred_at':'2026-04-03T09:15:00Z'},
        }
        for provider, value in expected.items():
            payload = json.loads((ROOT / 'samples' / f'{provider}.json').read_text())
            self.assertEqual(canonical_event(provider, payload), value)

    def test_unknown_and_missing_are_rejected(self):
        with self.assertRaises(ValueError): canonical_event('other', {})
        with self.assertRaises(ValueError): canonical_event('acme', {'event_id':'x'})

    def test_report_is_exact(self):
        report = json.loads((ROOT / 'provider_report.json').read_text())
        self.assertEqual(report['providers'], ['acme','orbit','zenith'])
        self.assertEqual(report['canonical_fields'], ['account_id','id','occurred_at','type'])

