import re

def _event_type(value: str) -> str:
    return re.sub(r'_+', '_', re.sub(r'[^a-z0-9]+', '_', value.lower())).strip('_')

def canonical_event(provider: str, payload: dict) -> dict:
    try:
        if provider == 'acme':
            values = (payload['event_id'], payload['event_name'], payload['meta']['account'], payload['created_at'])
        elif provider == 'orbit':
            values = (payload['id'], payload['topic'], payload['tenant_id'], payload['timestamp'])
        elif provider == 'zenith':
            values = (payload['delivery']['uuid'], payload['delivery']['kind'], payload['organization']['id'], payload['delivery']['sent_at'])
        else:
            raise ValueError(f'unknown provider: {provider}')
    except (KeyError, TypeError) as error:
        raise ValueError(f'missing webhook field for {provider}') from error
    event_id, event_type, account_id, occurred_at = values
    if not all(isinstance(value, str) and value for value in values):
        raise ValueError(f'invalid webhook field for {provider}')
    return {'id': event_id, 'type': _event_type(event_type), 'account_id': account_id, 'occurred_at': occurred_at}

