import json
import unittest
from pathlib import Path
from src.migrate_policy import migrate_policy

ROOT = Path(__file__).parents[1]

class MigrationTests(unittest.TestCase):
    def test_every_manifest_migrates(self):
        expected = {
            'auth': (12, 3, True), 'billing': (25, 5, True),
            'search': (8, 1, False), 'worker': (60, 2, True),
        }
        for service, values in expected.items():
            document = json.loads((ROOT / 'manifests' / f'{service}.json').read_text())
            migrated = migrate_policy(document)
            timeout, attempts, enabled = values
            self.assertEqual(migrated, {'schema_version':3,'service':service,'execution':{'timeout_seconds':timeout,'max_attempts':attempts},'access':{'enabled':enabled}})

    def test_bad_versions_and_values_fail(self):
        with self.assertRaises(ValueError): migrate_policy({'schema_version':9})
        with self.assertRaises(ValueError): migrate_policy({'schema_version':1,'service':'x','timeout':0,'retries':0,'allow':True})

    def test_report_is_exact(self):
        report = json.loads((ROOT / 'migration_report.json').read_text())
        self.assertEqual(report['services_by_source_version'], {'1':['auth','search'],'2':['billing','worker']})
        self.assertEqual(report['target_version'], 3)

