def migrate_policy(document: dict) -> dict:
    try:
        version = document['schema_version']
        service = document['service']
        if version == 1:
            timeout = document['timeout']
            attempts = document['retries'] + 1
            enabled = document['allow']
        elif version == 2:
            timeout = document['limits']['timeout_seconds']
            attempts = document['limits']['retry_count'] + 1
            enabled = document['enabled']
        else:
            raise ValueError(f'unsupported schema version: {version}')
    except (KeyError, TypeError) as error:
        raise ValueError('malformed service policy') from error
    if not isinstance(service, str) or not service or type(timeout) is not int or timeout <= 0 or type(attempts) is not int or attempts <= 0 or type(enabled) is not bool:
        raise ValueError('malformed service policy values')
    return {'schema_version': 3, 'service': service, 'execution': {'timeout_seconds': timeout, 'max_attempts': attempts}, 'access': {'enabled': enabled}}

