import json
import unittest
from pathlib import Path
from src.inventory import summarize_inventory

ROOT = Path(__file__).parents[1]

class InventoryTests(unittest.TestCase):
    def events(self):
        return [json.loads(line) for line in (ROOT / 'data/events.jsonl').read_text().splitlines()]

    def test_incident_events(self):
        self.assertEqual(summarize_inventory(self.events()), {'duplicates':1,'skus':{'A':{'on_hand':8,'reserved':1,'available':7},'B':{'on_hand':7,'reserved':3,'available':4}}})

    def test_invalid_sequence_is_rejected(self):
        with self.assertRaises(ValueError): summarize_inventory([{'id':'x','op':'ship','sku':'A','qty':1}])
        with self.assertRaises(ValueError): summarize_inventory([{'id':'x','op':'other','sku':'A','qty':1}])

    def test_written_summary(self):
        self.assertEqual(json.loads((ROOT / 'incident_summary.json').read_text()), summarize_inventory(self.events()))

