def summarize_inventory(events: list[dict]) -> dict:
    seen = set()
    duplicates = 0
    state = {}
    for event in events:
        try:
            event_id, op, sku, qty = event['id'], event['op'], event['sku'], event['qty']
        except (KeyError, TypeError) as error:
            raise ValueError('malformed inventory event') from error
        if event_id in seen:
            duplicates += 1
            continue
        seen.add(event_id)
        if type(qty) is not int or qty <= 0 or not isinstance(sku, str) or not sku:
            raise ValueError('invalid inventory event values')
        row = state.setdefault(sku, {'on_hand': 0, 'reserved': 0})
        if op == 'receive': row['on_hand'] += qty
        elif op == 'reserve': row['reserved'] += qty
        elif op == 'release': row['reserved'] -= qty
        elif op == 'ship':
            row['on_hand'] -= qty
            row['reserved'] -= qty
        else: raise ValueError(f'unknown operation: {op}')
        if row['on_hand'] < 0 or row['reserved'] < 0 or row['reserved'] > row['on_hand']:
            raise ValueError('invalid negative inventory state')
    skus = {sku: {**row, 'available': row['on_hand'] - row['reserved']} for sku, row in sorted(state.items())}
    return {'duplicates': duplicates, 'skus': skus}

