import csv
import io

def safe_csv_rows(schema: dict, tickets: list[dict]) -> tuple[str, dict]:
    columns = schema.get('columns')
    if not isinstance(columns, list) or not columns:
        raise ValueError('invalid schema')
    names = [column.get('name') for column in columns]
    types = [column.get('type') for column in columns]
    if any(not isinstance(name, str) or kind not in {'integer','text'} for name, kind in zip(names, types)):
        raise ValueError('invalid schema columns')
    output = io.StringIO(newline='')
    writer = csv.writer(output, lineterminator='\r\n')
    writer.writerow(names)
    sanitized = 0
    for ticket in tickets:
        row = []
        for name, kind in zip(names, types):
            if name not in ticket:
                raise ValueError(f'missing field: {name}')
            value = ticket[name]
            if kind == 'integer':
                if type(value) is not int: raise ValueError(f'wrong type: {name}')
            else:
                if not isinstance(value, str): raise ValueError(f'wrong type: {name}')
                if value.lstrip().startswith(('=', '+', '-', '@')):
                    value = "'" + value
                    sanitized += 1
            row.append(value)
        writer.writerow(row)
    report = {'rows': len(tickets), 'sanitized_cells': sanitized, 'columns': names}
    return output.getvalue(), report
